const ecrTagParameter = ssm.StringParameter.fromStringParameterAttributes(
  this,
  "EcrTagParameter",
  {
    parameterName: `/enpas/${props.environment}/backend-rails/image-tag`,
  },
);

const webAuthnOriginParameter = ssm.StringParameter.fromStringParameterName(
  this,
  "WebAuthnOriginParameter",
  `/enpas/${props.environment}/webauthn-origin`,
);
if (!ecrTagParameter) {
  throw new Error(
    `ECR tag parameter not found for /enpas/${props.environment}/backend-rails/image-tag`,
  );
}

const ecrTag = ecrTagParameter.stringValue;
const clusterName = `enpas-${props.environment}-ecs-cluster`;
